header_template:
{$I WaspLib/osrs.simba}
{$I behaviortree.simba}

var
  _LastDebugMsg: String;

//WriteLn wrapper with current time added, only logs a new msg if not similar to last one.
procedure log(s: string);
begin
  if (s = _LastDebugMsg) then Exit;
  _LastDebugMsg := s;
 WriteLn(GetTimeStamp('[hh:mm:ss:uu]') + ' ' + s);
end;

